    {
      "path": "src/main.tsx",
      "content": "import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './App.css';

ReactDOM.createRoot(document.getElementById('root') as HTMLElement).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
"
    },
    {
      "path": "src/App.tsx",
      "content": "import { useMemo, useState } from 'react';

type Page = 'overview' | 'routing' | 'report';

type Metric = {
  label: string;
  value: string;
  trend: string;
};

type Candidate = {
  name: string;
  score: string;
  role: string;
};

const metrics: Metric[] = [
  { label: 'Pass rate', value: '96.4%', trend: '+1.8%' },
  { label: 'Latency', value: '182 ms', trend: '-24 ms' },
  { label: 'Cost / 1k', value: '$0.18', trend: '-12%' },
  { label: 'Alpha / Beta', value: '0.72 / 0.28', trend: 'Stable' },
];

const candidates: Candidate[] = [
  { name: 'gpt-5.3-codex', score: '0.94', role: 'Primary reasoning' },
  { name: 'gpt-5.4-mini', score: '0.89', role: 'Fast fallback' },
  { name: 'gpt-5.4-nano', score: '0.81', role: 'Low-cost router' },
];

function IconSpark() {
  return (
    <span aria-hidden="true" style={{ display: 'inline-block', transform: 'translateY(1px)' }}>
      ✦
    </span>
  );
}

export default function App() {
  const [page, setPage] = useState<Page>('overview');

  const activeTitle = useMemo(() => {
    if (page === 'routing') return 'Routing Lab';
    if (page === 'report') return 'Eval Report';
    return 'Overview';
  }, [page]);

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div>
          <div className="brand-badge">Agent Sam</div>
          <h1 className="app-title">Command Center</h1>
          <p className="sidebar-copy">
            Thompson routing, evals, and model ops in one control surface.
          </p>
        </div>

        <nav className="nav" aria-label="Primary">
          <button
            className={page === 'overview' ? 'nav-btn active' : 'nav-btn'}
            onClick={() => setPage('overview')}
          >
            Overview
          </button>
          <button
            className={page === 'routing' ? 'nav-btn active' : 'nav-btn'}
            onClick={() => setPage('routing')}
          >
            Routing Lab
          </button>
          <button
            className={page === 'report' ? 'nav-btn active' : 'nav-btn'}
            onClick={() => setPage('report')}
          >
            Eval Report
          </button>
        </nav>

        <div className="sidebar-foot">
          <span className="status-dot" />
          <span>Live mock telemetry</span>
        </div>
      </aside>

      <main className="main">
        <header className="topbar">
          <div>
            <p className="eyebrow">Agent Sam Command Center</p>
            <h2 className="page-heading">{activeTitle}</h2>
          </div>
          <div className="topbar-chip">
            <IconSpark /> Build ready
          </div>
        </header>

        {page === 'overview' && (
          <section className="page-grid">
            <section className="hero card gradient" aria-label="Hero">
              <div>
                <p className="eyebrow">Thompson routing</p>
                <h3 className="hero-title">Confident model selection with crisp observability.</h3>
                <p>
                  Track pass rate, latency, cost, and alpha/beta routing decisions across the Agent Sam
                  stack.
                </p>
              </div>

              <div className="hero-panel">
                <div className="ring" title="Mock pass rate">
                  96.4%
                </div>
                <div className="hero-meta">
                  <div className="mini-label">Top candidate</div>
                  <strong>gpt-5.3-codex</strong>
                </div>
              </div>
            </section>

            <section className="metrics-row" aria-label="Metrics">
              {metrics.map((m) => (
                <article className="card metric-card" key={m.label}>
                  <span className="metric-label">{m.label}</span>
                  <strong className="metric-value">{m.value}</strong>
                  <small className="metric-trend">{m.trend}</small>
                </article>
              ))}
            </section>

            <section className="card content-card" aria-label="Candidate pool">
              <h4>Candidate pool</h4>
              <div className="candidate-list">
                {candidates.map((c) => (
                  <div className="candidate-row" key={c.name}>
                    <div>
                      <strong className="candidate-name">{c.name}</strong>
                      <p className="candidate-role">{c.role}</p>
                    </div>
                    <span className="candidate-score">{c.score}</span>
                  </div>
                ))}
              </div>
            </section>
          </section>
        )}

        {page === 'routing' && (
          <section className="page-grid two-col" aria-label="Routing Lab">
            <article className="card content-card">
              <h4>Routing controls</h4>
              <div className="stack">
                <div className="pill-row" aria-label="Thompson parameters">
                  <span className="pill active">alpha = 0.72</span>
                  <span className="pill">beta = 0.28</span>
                  <span className="pill">guardrail: on</span>
                </div>

                <div className="lab-box">
                  <p className="eyebrow">Decision snapshot</p>
                  <h3 className="lab-title">
                    Route complex prompts to <span className="model-strong">gpt-5.3-codex</span>, cheap requests to{' '}
                    <span className="model-strong">gpt-5.4-nano</span>.
                  </h3>
                  <p>
                    gpt-5.4-mini remains the fallback for balanced speed and quality.
                  </p>
                </div>

                <div className="divider" />

                <div className="sim-row" aria-label="Mock routing">
                  <div className="sim-card">
                    <div className="sim-top">Sample prompt</div>
                    <div className="sim-text">
                      “Refactor a TypeScript service with streaming output + robust error handling.”
                    </div>
                    <div className="sim-tag">Chosen: gpt-5.3-codex</div>
                  </div>
                  <div className="sim-card subtle">
                    <div className="sim-top">Budget task</div>
                    <div className="sim-text">“Summarize log lines in one paragraph.”</div>
                    <div className="sim-tag">Chosen: gpt-5.4-nano</div>
                  </div>
                </div>
              </div>
            </article>

            <article className="card content-card">
              <h4>Live ladder</h4>
              <div className="ladder" aria-label="Model ladder">
                <div className="ladder-row">
                  <span>gpt-5.3-codex</span>
                  <em>0.94</em>
                </div>
                <div className="ladder-row">
                  <span>gpt-5.4-mini</span>
                  <em>0.89</em>
                </div>
                <div className="ladder-row">
                  <span>gpt-5.4-nano</span>
                  <em>0.81</em>
                </div>
              </div>

              <div className="ladder-foot">
                <div className="mini-metric">
                  <div className="mini-label">Exploration</div>
                  <div className="mini-value">Low</div>
                </div>
                <div className="mini-metric">
                  <div className="mini-label">Safety gate</div>
                  <div className="mini-value">Pass</div>
                </div>
              </div>

              <div className="divider" />

              <div className="note">
                Thompson samples update on mock eval signals. This UI is intentionally self-contained.
              </div>
            </article>
          </section>
        )}

        {page === 'report' && (
          <section className="page-grid" aria-label="Eval Report">
            <article className="card content-card report-card">
              <h4>Eval summary</h4>
              <div className="report-grid">
                <div className="report-item">
                  <span>Pass rate</span>
                  <strong>96.4%</strong>
                </div>
                <div className="report-item">
                  <span>Latency p95</span>
                  <strong>244 ms</strong>
                </div>
                <div className="report-item">
                  <span>Cost delta</span>
                  <strong>-12%</strong>
                </div>
                <div className="report-item">
                  <span>Routing drift</span>
                  <strong>0.03</strong>
                </div>
              </div>

              <div className="barset" aria-label="Candidate performance bars">
                <div className="bar-row">
                  <div className="bar-head">
                    <span className="bar-name">gpt-5.3-codex</span>
                    <span className="bar-num">Pass 97.8%</span>
                  </div>
                  <div className="bar"><div className="bar-fill fill-a" /></div>
                </div>
                <div className="bar-row">
                  <div className="bar-head">
                    <span className="bar-name">gpt-5.4-mini</span>
                    <span className="bar-num">Pass 96.1%</span>
                  </div>
                  <div className="bar"><div className="bar-fill fill-b" /></div>
                </div>
                <div className="bar-row">
                  <div className="bar-head">
                    <span className="bar-name">gpt-5.4-nano</span>
                    <span className="bar-num">Pass 93.9%</span>
                  </div>
                  <div className="bar"><div className="bar-fill fill-c" /></div>
                </div>
              </div>
            </article>

            <article className="card content-card">
              <h4>Routing notes</h4>
              <ul className="notes-list">
                <li>
                  <strong>gpt-5.3-codex</strong> leads accuracy-sensitive traffic.
                </li>
                <li>
                  <strong>gpt-5.4-mini</strong> is consistent under burst load.
                </li>
                <li>
                  <strong>gpt-5.4-nano</strong> preserves budget on short tasks.
                </li>
              </ul>

              <div className="quote">
                <div className="quote-mark">“</div>
                <div className="quote-text">
                  The Command Center keeps the feedback loop tight: sample → route → evaluate → update.
                </div>
              </div>
            </article>
          </section>
        )}
      </main>
    </div>
  );
}
"
    },
    {
      "path": "src/App.css",
      "content": ":root {
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  color: #e8ecff;
  background: radial-gradient(circle at top, #1d2b5a 0%, #0b1020 45%, #070b14 100%);
  line-height: 1.5;
  font-weight: 400;
}

* { box-sizing: border-box; }
body { margin: 0; min-width: 320px; background: transparent; }
button { font: inherit; }

.app-shell {
  min-height: 100vh;
  display: grid;
  grid-template-columns: 280px 1fr;
}

.sidebar {
  padding: 28px;
  background: rgba(7, 11, 20, 0.72);
  border-right: 1px solid rgba(255,255,255,0.08);
  backdrop-filter: blur(18px);
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  gap: 18px;
}

.brand-badge {
  width: fit-content;
  padding: 8px 12px;
  background: linear-gradient(135deg, #7c5cff, #33d6ff);
  color: white;
  font-weight: 800;
  border-radius: 999px;
  box-shadow: 0 16px 44px rgba(124, 92, 255, 0.25);
}

.app-title {
  margin: 12px 0 8px;
  font-size: 1.25rem;
  letter-spacing: 0.2px;
}

.sidebar-copy {
  margin: 0;
  color: rgba(232,236,255,0.78);
  max-width: 220px;
}

.nav { display: grid; gap: 10px; margin: 6px 0 0; }
.nav-btn {
  border: 1px solid rgba(255,255,255,0.1);
  background: rgba(255,255,255,0.04);
  color: #e8ecff;
  padding: 12px 14px;
  text-align: left;
  cursor: pointer;
  border-radius: 16px;
  transition: transform 140ms ease, border-color 160ms ease, background 160ms ease;
}
.nav-btn:hover { transform: translateY(-1px); border-color: rgba(255,255,255,0.22); }
.nav-btn.active {
  background: linear-gradient(135deg, rgba(124,92,255,0.35), rgba(51,214,255,0.22));
  border-color: rgba(124,92,255,0.55);
}

.sidebar-foot {
  display: flex;
  gap: 10px;
  align-items: center;
  color: rgba(232,236,255,0.7);
  font-size: 0.92rem;
}

.status-dot {
  width: 10px;
  height: 10px;
  background: #40f0a5;
  box-shadow: 0 0 18px #40f0a5;
  border-radius: 999px;
}

.main { padding: 28px; }
.topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 22px;
  gap: 14px;
}

.eyebrow {
  text-transform: uppercase;
  letter-spacing: 0.16em;
  font-size: 0.72rem;
  color: #8fb6ff;
  margin: 0 0 6px;
}

.page-heading {
  margin: 0;
  font-size: 1.7rem;
  letter-spacing: -0.02em;
}

.topbar-chip {
  padding: 10px 14px;
  background: rgba(255,255,255,0.08);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 999px;
  color: rgba(232,236,255,0.92);
  box-shadow: 0 20px 70px rgba(0,0,0,0.18);
  white-space: nowrap;
}

.page-grid { display: grid; gap: 18px; }
.two-col { grid-template-columns: 1.2fr 0.8fr; }

.card {
  padding: 22px;
  background: rgba(10, 16, 32, 0.72);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 18px;
  box-shadow: 0 18px 60px rgba(0,0,0,0.28);
}

.gradient {
  background: linear-gradient(135deg, rgba(124,92,255,0.28), rgba(51,214,255,0.12));
}

.hero {
  display: flex;
  justify-content: space-between;
  gap: 20px;
  align-items: center;
}

.hero-title { margin: 0; font-size: 1.3rem; letter-spacing: -0.02em; }

.hero-panel { display: grid; gap: 12px; justify-items: center; min-width: 180px; }
.hero-meta { display: grid; gap: 6px; text-align: center; }
.mini-label { color: rgba(232,236,255,0.7); font-size: 0.82rem; }

.ring {
  width: 120px;
  height: 120px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  background: conic-gradient(#33d6ff 0 96%, rgba(255,255,255,0.15) 96% 100%);
  color: #06111f;
  font-weight: 900;
  font-size: 1.4rem;
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.15);
}

.metrics-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 18px; }

.metric-card { display: grid; gap: 10px; }
.metric-label { color: rgba(232,236,255,0.72); font-size: 0.95rem; }
.metric-value { font-size: 1.5rem; letter-spacing: -0.02em; margin-top: 0; }
.metric-trend { color: rgba(232,236,255,0.72); }

.content-card { display: grid; gap: 16px; }
.content-card h4 { margin: 0; font-size: 1.08rem; }

.candidate-list, .ladder, .report-grid { display: grid; gap: 12px; }

.candidate-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 16px;
  background: rgba(255,255,255,0.04);
  border-radius: 14px;
  border: 1px solid rgba(255,255,255,0.06);
}

.candidate-name { display: block; font-weight: 800; }
.candidate-role { margin: 4px 0 0; color: rgba(232,236,255,0.72); font-size: 0.9rem; }
.candidate-score { color: rgba(232,236,255,0.92); font-weight: 800; }

.stack { display: grid; gap: 16px; }

.pill-row { display: flex; gap: 10px; flex-wrap: wrap; }
.pill {
  padding: 8px 12px;
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 999px;
  color: rgba(232,236,255,0.84);
  font-size: 0.95rem;
}
.pill.active { background: rgba(64,240,165,0.15); color: #c9ffe9; border-color: rgba(64,240,165,0.35); }

.lab-box {
  padding: 18px;
  border-radius: 16px;
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.06);
}

.lab-title { margin: 0 0 10px; font-size: 1.2rem; letter-spacing: -0.02em; }
.model-strong { color: rgba(232,236,255,0.98); font-weight: 900; }

.divider { height: 1px; background: rgba(255,255,255,0.08); margin: 4px 0; }

.sim-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sim-card {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.06);
  border-radius: 16px;
  padding: 14px;
}
.sim-card.subtle { background: rgba(255,255,255,0.03); }
.sim-top { color: rgba(143,182,255,0.9); font-size: 0.85rem; text-transform: uppercase; letter-spacing: 0.12em; }
.sim-text { margin-top: 8px; color: rgba(232,236,255,0.86); font-weight: 650; }
.sim-tag {
  margin-top: 12px;
  display: inline-block;
  padding: 7px 10px;
  border-radius: 999px;
  background: rgba(124,92,255,0.18);
  border: 1px solid rgba(124,92,255,0.35);
  color: rgba(232,236,255,0.92);
  font-weight: 800;
  font-size: 0.92rem;
}

.ladder {
  display: grid;
  gap: 10px;
}

.ladder-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 16px;
  background: rgba(255,255,255,0.04);
  border-radius: 14px;
  border: 1px solid rgba(255,255,255,0.06);
}

.ladder-row span { font-weight: 800; }
.ladder-row em { font-style: normal; color: rgba(232,236,255,0.82); font-weight: 900; }

.ladder-foot { display: flex; gap: 12px; margin-top: 2px; justify-content: space-between; }
.mini-metric { padding: 12px 14px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.06); width: 100%; }
.mini-value { margin-top: 6px; font-weight: 950; letter-spacing: -0.02em; }

.note { color: rgba(232,236,255,0.72); line-height: 1.6; }

.report-card { gap: 14px; }
.report-grid {
  grid-template-columns: 1fr 1fr;
}
.report-item {
  padding: 14px 16px;
  border-radius: 14px;
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.06);
}
.report-item span { color: rgba(232,236,255,0.72); display: block; }
.report-item strong { font-size: 1.45rem; display: block; margin-top: 8px; letter-spacing: -0.02em; }

.barset { display: grid; gap: 12px; margin-top: 4px; }
.bar-row { display: grid; gap: 8px; }
.bar-head { display: flex; justify-content: space-between; gap: 10px; }
.bar-name { font-weight: 900; }
.bar-num { color: rgba(232,236,255,0.72); }
.bar {
  height: 12px;
  border-radius: 999px;
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.08);
  overflow: hidden;
}
.bar-fill {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, rgba(124,92,255,0.85), rgba(51,214,255
